import{_ as r,o as t,c as e,a2 as l}from"./chunks/framework.VxKNwi4m.js";const u=JSON.parse('{"title":"거래 내역 관리","description":"","frontmatter":{},"headers":[],"relativePath":"ledger/manage.md","filePath":"ledger/manage.md","lastUpdated":1783350124000}'),o={name:"ledger/manage.md"};function i(n,a,s,h,d,g){return t(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="거래-내역-관리" tabindex="-1">거래 내역 관리 <a class="header-anchor" href="#거래-내역-관리" aria-label="Permalink to &quot;거래 내역 관리&quot;">​</a></h1><p>프로젝트에서 발생하는 모든 실제 입출금 내역을 기록하고, 이를 회계 계정 및 계약 정보와 연결하여 관리하는 핵심 페이지입니다.</p><ul><li><strong>위치</strong>: <code>회계 자금 관리 &gt; 거래 내역 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>통장상의 실제 거래 데이터(은행거래내역)를 등록하고, 각 거래가 회계상 어떤 의미(분류 내역)를 갖는지 정의합니다. 하나의 거래를 여러 계정으로 나누는 분할 전표 처리를 지원하며, 분양 수입 등 특정 계정의 경우 실제 계약자 정보와 연결하여 수납 장부의 정확성을 확보합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>상세 필터링 및 검색</strong>: 기간, 계정 과목, 거래 계좌, 계약 정보 등 다양한 조건으로 거래 조회</li><li><strong>다수 거래 일괄 등록</strong>: 한 화면에서 여러 건의 독립된 은행 거래를 동시에 입력 가능</li><li><strong>엑셀 연동</strong>: 분류 내역 엑셀 템플릿 업로드 및 현재 목록의 엑셀 추출 지원</li><li><strong>분할 전표 지원</strong>: 하나의 입/출금 건을 여러 개의 회계 계정으로 상세 분류 가능</li><li><strong>계약/계약자 필수 매칭</strong>: 수납 관련 계정 선택 시 관련 계약 정보를 연동하여 데이터 정합성 유지</li><li><strong>인라인 편집</strong>: 목록 화면에서 적요, 메모, 금액 등을 이동 없이 즉시 수정</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-목록-제어-및-필터링" tabindex="-1">1. 목록 제어 및 필터링 <a class="header-anchor" href="#_1-목록-제어-및-필터링" aria-label="Permalink to &quot;1. 목록 제어 및 필터링&quot;">​</a></h3><p>원하는 거래 내역을 신속하게 찾기 위한 검색 영역입니다.</p><ul><li><strong>검색 조건</strong>: 거래일자 범위, 입출금 구분, 계정 분류(자산/부채/수익/비용 등), 상세 계정 과목, 거래 계좌 등</li><li><strong>전체(운영비용 포함) 보기</strong>: 체크 시 일반 사업비 외에 운영비용(전도금) 계좌의 내역까지 통합 조회합니다.</li></ul><h3 id="_2-입출금-현황-목록" tabindex="-1">2. 입출금 현황 목록 <a class="header-anchor" href="#_2-입출금-현황-목록" aria-label="Permalink to &quot;2. 입출금 현황 목록&quot;">​</a></h3><p>조회된 거래 내역을 표시하며, 각 행은 &#39;은행거래내역&#39;과 &#39;분류 내역&#39;으로 나뉩니다.</p><ul><li><strong>은행거래내역</strong>: 실제 통장에 기록된 날짜, 계좌명, 적요, 입/출금액 정보</li><li><strong>분류 내역</strong>: 해당 거래가 회계 장부에 기록되는 계정명, 거래처, 분류 금액 및 지출 증빙 정보</li><li><strong>금액 검증</strong>: 은행 거래 금액과 하단 분류 내역의 합계가 일치하면 초록색 체크 아이콘(✅)이 표시됩니다. 일치하지 않을 경우 경고 메시지와 함께 차액을 안내합니다.</li></ul><h3 id="_3-거래-등록-및-수정" tabindex="-1">3. 거래 등록 및 수정 <a class="header-anchor" href="#_3-거래-등록-및-수정" aria-label="Permalink to &quot;3. 거래 등록 및 수정&quot;">​</a></h3><p>새로운 입출금 내역을 생성하거나 기존 내역을 상세 수정하는 화면입니다.</p><ul><li><strong>은행거래건 추가</strong>: 신규 등록 시 여러 건의 거래를 한 번에 추가하여 작업 시간을 단축할 수 있습니다.</li><li><strong>이체수수료 자동 입력</strong>: 출금 항목 옆의 아이콘을 클릭하면 설정된 이체 수수료(예: 500원) 분개를 자동으로 생성합니다.</li><li><strong>대체 거래 자동 감지</strong>: 출금 거래 시 &#39;대체(출금)&#39; 계정을 선택하면, 상대 계좌로 들어오는 &#39;대체(입금)&#39; 거래건을 시스템이 자동으로 추가 생성합니다.</li></ul><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="계정별-필수-정보-매칭" tabindex="-1">계정별 필수 정보 매칭 <a class="header-anchor" href="#계정별-필수-정보-매칭" aria-label="Permalink to &quot;계정별 필수 정보 매칭&quot;">​</a></h3><p>분양수입, 미수금, 미지급금 등 <strong>계약 정보와 직접 연결되는 계정</strong>을 선택하면 시스템이 자동으로 [계약 정보 선택] 창을 띄웁니다. 이를 통해 수납 관리 메뉴와 회계 관리 메뉴의 데이터가 완벽하게 일치하게 됩니다.</p><h3 id="엑셀-업로드-및-템플릿" tabindex="-1">엑셀 업로드 및 템플릿 <a class="header-anchor" href="#엑셀-업로드-및-템플릿" aria-label="Permalink to &quot;엑셀 업로드 및 템플릿&quot;">​</a></h3><p>대량의 공사비 집행이나 미납금 일괄 정산 시 유용합니다. 상단의 [다운로드] 아이콘으로 템플릿을 내려받아 내용을 작성한 후 [업로드] 아이콘으로 불러오면 복잡한 분개 내역을 한 번에 입력할 수 있습니다.</p><h3 id="수정-제한-정산-보호" tabindex="-1">수정 제한 (정산 보호) <a class="header-anchor" href="#수정-제한-정산-보호" aria-label="Permalink to &quot;수정 제한 (정산 보호)&quot;">​</a></h3><p>정산이 완료된 일자 이전의 거래나 특정 기간(기본 10일)이 지난 과거 데이터는 데이터 무결성을 위해 일반 권한으로 수정이 제한될 수 있습니다. 중요한 과거 데이터 수정은 관리자에게 문의하십시오.</p>',24)])])}const p=r(o,[["render",i]]);export{u as __pageData,p as default};
